insert into forecast_sources
(source_id,source_name,publisher,jpas_tiers,attribute_codes,horizon_end_year,horizon_tier,cadence,latest_vintage,dc_specific,geography_scope,machine_access,revision_signal,archive_recoverable,primary_url,archive_url,faraday_read,status)
values
('colorado-river-basin-reclamation-crss-24-month-study-post','Colorado River Basin — Reclamation CRSS / 24-Month Study / Post-2026 Ops','U.S. Bureau of Reclamation','{"WTR — Water & Cooling"}','{"WTR-03","WTR-09"}',2060,'Long-Range (2045+)','Continuous / Rolling','Aug 2025 24-Month Study; Post-2026 Draft EIS (2026)','No — infra baseline','Colorado River Basin — 7 states (AZ, NV, CA, CO, UT, WY, NM)','Mixed','High','Yes — Publisher archive','https://www.usbr.gov/ColoradoRiverBasin/post2026/index.html','https://www.usbr.gov/lc/region/g4000/riverops/24ms-projections.html','The master constraint over every Southwest DC market (Phoenix, Las Vegas, Southern California). CRSS models Lake Powell/Mead through ~2060; the Post-2026 operating rules (Draft EIS comment period closed Mar 2, 2026; preferred alternative expected summer 2026) will reset shortage tiers for the entire Lower Basin. Lake Mead has been in shortage since 2022. Not DC-specific — this is the basin-scale spine every AZ/NV/CA water source hangs from. Verify current tier and study dates before subscriber-facing use.','Cataloged'),
('dominion-energy-virginia-20-year-data-center-load-forecast','Dominion Energy Virginia 20-Year Data Center Load Forecast','Dominion Energy (via PJM Load Analysis Subcommittee)','{"PWR — Power & Energy","Cross-Cutting Demand"}','{"PWR-08","pure DC demand"}',2046,'Extended (15–20 yr)','Annual','2025 filing','Yes — explicit DC load','Dominion Energy Virginia territory (Loudoun / Northern Virginia core)','PDF Only','High','Partial','https://www.pjm.com/committees-and-groups/subcommittees/las',null,'Rare pure-DC demand curve. Recent vintage shows roughly 16.6 GW of DC demand by the mid-2040s against 40+ GW of contracted/requested interconnection — the contracted-vs-forecast gap is itself a high-value signal. Ground zero for the world''s densest DC jurisdiction.','Validated'),
('ercot-long-term-load-forecast','ERCOT Long-Term Load Forecast','ERCOT','{"PWR — Power & Energy","Cross-Cutting Demand"}','{"PWR-04","PWR-08","large-load interconnection"}',2032,'Medium (8–12 yr)','Annual','2025','Partial — sector-level','ERCOT (most of Texas)','Mixed','High','Partial','https://www.ercot.com/gridinfo/load/forecast',null,'Texas large-load interconnection is exploding; ERCOT''s revised peak-demand curve reflects DC + crypto + electrification. The Large Load Interconnection data set is a distinct, high-value companion feed for jurisdiction-level DC siting signals.','Validated'),
('texas-state-water-plan','Texas State Water Plan','Texas Water Development Board (TWDB)','{"WTR — Water & Cooling"}','{"WTR-01","WTR-02","WTR-03","supply/demand"}',2080,'Long-Range (2045+)','Periodic','Draft 2027 Plan (2030–2080); adopted 2022 Plan (2020–2070)','No — infra baseline','Texas (16 regional planning groups, county-level)','Mixed','High','Yes — Publisher archive','https://www.twdb.texas.gov/waterplanning/swp/2027/index.asp','https://www.twdb.texas.gov/waterplanning/swp/','Deepest long-range water forecast of any U.S. state, reaching 2080. County-level supply/demand under a drought-of-record scenario. Strong revision signal: the Draft 2027 plan more than doubled required capital (~$80B → ~$174B) vs 2022 and extended the horizon 2070→2080; existing supplies projected to fall ~10% while demand rises. The template for water-side jurisdiction intelligence.','Priority Ingest'),
('bls-employment-projections','BLS Employment Projections','U.S. Bureau of Labor Statistics','{"LBR — Labor & Workforce"}','{"LBR-01","LBR-03","LBR-04","LBR-07"}',2034,'Medium (8–12 yr)','Annual','2024–2034 projections','No — infra baseline','United States (national; occupation & industry incl. NAICS 23 construction)','Bulk Download','Medium','Yes — Publisher archive','https://www.bls.gov/emp/',null,'Ten-year national workforce outlook, now issued annually. 2024–2034 cycle: total employment 170.0M → 175.2M (+3.1%); construction & extraction grow faster than average with ~649,300 annual openings. Maps to LBR construction-employment and skilled-trades attributes. National only — pair with Projections Central for jurisdiction detail.','Validated'),
('ntia-bead-and-state-broadband-deployment-plans','NTIA BEAD & State Broadband Deployment Plans','NTIA / State Broadband Offices','{"NET — Connectivity"}','{"NET-04","NET-07","deployment pipeline"}',null,'Near-Term (≤5 yr)','Ad hoc','State Final Proposals / deployment plans (2025–2026)','No — infra baseline','United States (state / sub-state deployment areas)','Mixed','Medium','Partial','https://www.internetforall.gov/',null,'Not a demand forecast — a forward deployment pipeline. State BEAD final proposals map where middle-mile / last-mile fiber is funded to be built over the coming years, feeding NET-07. Signals future connectivity in currently thin jurisdictions. Subject to federal policy revision — track status.','Cataloged'),
('california-water-plan-update-2023-update-2028-in-development','California Water Plan (Update 2023; Update 2028 in development)','California Department of Water Resources (DWR)','{"WTR — Water & Cooling"}','{"WTR-01","WTR-03"}',2072,'Long-Range (2045+)','Periodic','Update 2023','Partial — sector-level','California — statewide + hydrologic regions','Mixed','Medium','Yes — Publisher archive','https://water.ca.gov/programs/california-water-plan','https://data.cnra.ca.gov/dataset/weap-future-scenarios-model-for-water-plan-update-2023','5-year statutory cadence. WEAP-CVPA future-scenarios model publishes machine-readable outputs via the CNRA open-data portal. Update 2028 sets an interim goal to identify 9 maf of additional supply by 2040. Scenario horizons run to ~2072 (some end-of-century). VERIFY horizon-year specifics before subscriber-facing use.','Cataloged'),
('wri-aqueduct-4-0-future-projections','WRI Aqueduct 4.0 — Future Projections','World Resources Institute','{"WTR — Water & Cooling","ENV — Environmental Risk"}','{"WTR-03","WTR-08","basin water stress"}',2080,'Long-Range (2045+)','Periodic','Aqueduct 4.0 (2023); future-annual dataset','No — infra baseline','Global (hydrological basins / sub-catchment)','Bulk Download','Medium','Yes — Publisher archive','https://www.wri.org/data/aqueduct-water-risk-atlas','https://developers.google.com/earth-engine/datasets/catalog/WRI_Aqueduct_Water_Risk_V4_future_annual','The ''future annual'' layer projects baseline water stress, demand and supply to 2030 / 2050 / 2080 under business-as-usual, optimistic and pessimistic pathways. Feeds WTR-03 (basin stress). The only global, machine-readable long-range water-stress projection — the water-side analog to a long-term load forecast.','Priority Ingest'),
('snwa-water-resource-plan-50-year','SNWA Water Resource Plan (50-Year)','Southern Nevada Water Authority (SNWA)','{"WTR — Water & Cooling"}','{"WTR-01","WTR-03"}',2076,'Long-Range (2045+)','Annual','2026 plan (published Aug 2025)','Partial — sector-level','Southern Nevada / Las Vegas Valley / Clark County','PDF Only','High','Yes — Publisher archive','https://www.snwa.com/water-resources/water-resource-plan/index.html','https://www.snwa.com/assets/pdf/water-resource-plan-2026.pdf','50-year rolling horizon, maintained annually since 1996 (clean vintage series). ~90% of supply from Lake Mead / Colorado River → downstream of the Reclamation record. Directly DC-cooling relevant: SNWA''s Feb 2024 ban on evaporative cooling in new commercial construction is the most aggressive DC water policy in the US. Context: 23 Southern Nevada DCs consumed 716M gallons in 2024 (Google Henderson 352M). Evaporative cooling = ~10% of Southern Nevada''s Colorado River allocation. VERIFY figures before subscriber-facing use.','Cataloged'),
('2023-colorado-water-plan-analysis-and-technical-update-basin','2023 Colorado Water Plan + Analysis & Technical Update (Basin Implementation Plans)','Colorado Water Conservation Board (CWCB)','{"WTR — Water & Cooling"}','{"WTR-01","WTR-03"}',2050,'Long-Range (2045+)','Periodic','2023 Plan; 2022 Basin Implementation Plans','Partial — sector-level','Colorado — statewide, 8 basins (Front Range growth)','Mixed','Medium','Yes — Publisher archive','https://cwcb.colorado.gov/colorado-water-plan','https://cwcb.colorado.gov/colorado-water-plan/technical-update-to-the-plan','Water ''gap'' projected to 2050. Municipal & Industrial demand modeled under 6 scenarios (Baseline, Business as Usual, Weak Economy, Cooperative Growth, Adaptive Innovation, Hot Growth) in the Analysis & Technical Update (2019, formerly SWSI), refreshed by 2022 Basin Implementation Plans — statewide summary values shifted between updates, a documented revision path. Not DC-specific; M&I sector-level. VERIFY scenario figures before subscriber-facing use.','Cataloged'),
('pjm-long-term-load-forecast','PJM Long-Term Load Forecast','PJM Interconnection','{"PWR — Power & Energy","Cross-Cutting Demand"}','{"PWR-04","PWR-08","DC large-load"}',2046,'Extended (15–20 yr)','Annual','2026 Load Forecast (extended to 20 yr per FERC Order 1920)','Partial — sector-level','PJM footprint (13 states + DC), zonal incl. Dominion (DOM)','Mixed','High','Yes — Publisher archive','https://www.pjm.com/-/media/DotCom/library/reports-notices/load-forecast/','https://www.pjm.com/-/media/DotCom/library/reports-notices/load-forecast/','Canonical revision example: the Dominion-zone 2037 DC projection rose from ~5,700 MW (2022 vintage) to 20,000+ MW (2025 vintage). Extended from 15 to 20 years in 2025. Zonal detail makes it the sharpest instrument for tracking DC-driven load escalation and vintage revisions in the #1 U.S. DC market.','Priority Ingest'),
('adwr-water-supply-and-demand-reports-arizona-assured-water','ADWR Water Supply & Demand Reports + Arizona Assured Water Supply (AAWS)','Arizona Department of Water Resources (ADWR)','{"WTR — Water & Cooling"}','{"WTR-01","WTR-03","WTR-10"}',2075,'Long-Range (2045+)','Annual','2024 model update','Partial — sector-level','Arizona — by groundwater basin (Phoenix & Pinal AMAs)','Mixed','High','Yes — Publisher archive','https://www.azwater.gov/supply-demand','https://www.azwater.gov/adwr-data-dashboards','Projections 1990–2075 by groundwater basin. High revision cadence: unmet-demand estimate revised 4.86 maf → 3.6 maf between June 2023 and June 2024 model runs — a clean example of vintage-over-vintage drift to track. AAWS 100-year assured-supply test functions as a hard siting gate for new large water users incl. data centers. VERIFY figures before subscriber-facing use.','Priority Ingest'),
('lbnl-u-s-data-center-energy-usage-report','LBNL — U.S. Data Center Energy Usage Report','Lawrence Berkeley National Laboratory (for U.S. DOE)','{"PWR — Power & Energy","Cross-Cutting Demand"}','{"Cross-cutting DC load"}',2028,'Near-Term (≤5 yr)','Periodic','2024 report','Yes — explicit DC load','United States','PDF Only','Medium','Yes — Publisher archive','https://eta.lbl.gov/publications',null,'The authoritative U.S. bottom-up DC electricity estimate. 2024 edition: DC load rising from ~176 TWh (2023) toward ~325–580 TWh by 2028 (6.7–12% of U.S. electricity). Short horizon, but the empirical anchor other forecasts calibrate against.','Validated'),
('colorado-river-basin-operations-crss-24-month-study-and','Colorado River Basin Operations — CRSS, 24-Month Study & Post-2026 Guidelines','U.S. Bureau of Reclamation','{"WTR — Water & Cooling"}','{"WTR-09","WTR-03"}',2060,'Long-Range (2045+)','Continuous / Rolling','Aug 2025 24-Month Study; Post-2026 Draft EIS (2026)','No — infra baseline','Colorado River Basin (AZ, NV, CA, CO, UT, WY, NM)','Mixed','High','Yes — Publisher archive','https://www.usbr.gov/ColoradoRiverBasin/post2026/index.html','https://www.usbr.gov/lc/region/g4000/riverops/24ms-projections.html','The multi-state supply spine beneath Arizona and Nevada. Post-2026 Draft EIS shapes operations through ~2060 (comment period closed Mar 2, 2026; preferred alternative expected summer 2026). Aug 2025 24-Month Study sets 2026 Powell/Mead operations; Mead currently in Level 1 Shortage. High revision cadence via monthly/continuous model runs. VERIFY operational status before subscriber-facing use.','Cataloged'),
('projections-central-state-occupational-projections','Projections Central — State Occupational Projections','Projections Central (BLS-funded consortium)','{"LBR — Labor & Workforce"}','{"LBR-01","LBR-04","LBR-07","state-level"}',null,'Medium (8–12 yr)','Annual','Latest state long-term (10-yr) and short-term (2-yr) cycles','No — infra baseline','All U.S. states (state-level occupational)','Bulk Download','Low','Partial','https://projectionscentral.org/',null,'The jurisdiction-level companion to BLS EP: 10-year occupational and industry projections for every state, from state labor-market agencies. Enables LBR forecasting down to the state a jurisdiction sits in — critical for construction and skilled-trades supply near candidate DC sites.','Cataloged'),
('eia-annual-energy-outlook-aeo','EIA Annual Energy Outlook (AEO)','U.S. Energy Information Administration','{"PWR — Power & Energy","Cross-Cutting Demand"}','{"PWR-07","PWR-08","cross-cutting DC load"}',2050,'Long-Range (2045+)','Annual','AEO 2025 (AEO 2026 pending)','Partial — sector-level','United States (national + census/EMM regions)','API','High','Yes — Publisher archive','https://www.eia.gov/outlooks/aeo/','https://www.eia.gov/outlooks/aeo/archive.php','Only major U.S. source modeling electricity demand all the way to 2050. Commercial-sector server/DC electricity is modeled explicitly in recent vintages; 2050 DC-adjacent figures span a wide range across cases. Prior AEOs are archived by the publisher — a clean vintage-over-vintage series as DC-load assumptions were progressively added.','Priority Ingest'),
('georgia-regional-water-plans-water-demand-forecast-dashboard','Georgia Regional Water Plans + Water Demand Forecast Dashboard','Georgia Environmental Protection Division (EPD)','{"WTR — Water & Cooling"}','{"WTR-01","WTR-03"}',2060,'Long-Range (2045+)','Periodic','2023 Regional Water Plans','Partial — sector-level','Georgia — 10 regional water planning councils','Mixed','Medium','Yes — Publisher archive','https://waterplanning.georgia.gov/forecasting','https://waterplanning.georgia.gov/regional-water-plan','Atlanta is a fast-growing Southeast DC market. Georgia forecasts Municipal / Industrial / Agricultural / Energy water use in 10-year increments to 2060, and uniquely breaks out an Energy-water category (thermoelectric cooling) — a native PWR×WTR crosswalk for joint power-and-water siting analysis. Clean multi-vintage series (2011 → 2017 → 2023) supports revision tracking.','Cataloged'),
('iea-energy-and-ai','IEA — Energy and AI','International Energy Agency','{"PWR — Power & Energy","Cross-Cutting Demand"}','{"Cross-cutting DC electricity demand"}',2035,'Medium (8–12 yr)','Periodic','2025 report (2026 update expected)','Yes — explicit DC load','Global + major regions (US, China, EU)','Mixed','Medium','Yes — Publisher archive','https://www.iea.org/reports/energy-and-ai',null,'Most-cited global DC electricity outlook. Four scenarios to 2035; the base case roughly doubles global DC electricity 2025→2030 (~485→~950 TWh) toward ~1,200 TWh by 2035. The scenario spread — the gap between the high and low cases — is the intelligence, framing global DC-power uncertainty.','Validated'),
('miso-long-term-mtep-load-forecast','MISO Long-Term / MTEP Load Forecast','Midcontinent Independent System Operator','{"PWR — Power & Energy"}','{"PWR-04","PWR-08"}',2035,'Medium (8–12 yr)','Annual','2025 (MTEP cycle)','Partial — sector-level','MISO footprint (15 states, Central U.S.)','Mixed','Medium','Partial','https://www.misoenergy.org/planning/',null,'Recent MISO planning shows demand climbing from ~121 GW toward ~163 GW (2025→2035) — a large upward revision driven by data centers and manufacturing reshoring. Key for Midwest jurisdictions (IN, IL, MI, IA, MN).','Cataloged'),
('usgs-water-use-in-the-united-states','USGS Water Use in the United States','U.S. Geological Survey','{"WTR — Water & Cooling"}','{"WTR-01","WTR-06","withdrawals baseline"}',null,null,'Periodic','2020 compilation (released 2023)','No — infra baseline','United States (county-level withdrawals by category)','Bulk Download','Low','Yes — Publisher archive','https://www.usgs.gov/mission-areas/water-resources/science/water-use-united-states',null,'Not a forecast — the authoritative county-level baseline of actual water withdrawals (thermoelectric, public supply, industrial), compiled every 5 years. Calibration input against which forward water-stress projections (Aqueduct, state plans) are anchored.','Cataloged'),
('ncsl-legislation-and-incentive-tracking','NCSL — Legislation & Incentive Tracking','National Conference of State Legislatures','{"REG — Regulatory","INC — Incentives"}','{"REG-10","INC-10","legislative pipeline"}',null,null,'Continuous / Rolling','Rolling (current legislative sessions)','Partial — sector-level','All U.S. states','HTML Tables','Medium','Partial','https://www.ncsl.org/',null,'Not a forecast — the forward-signal source for REG/INC, tiers that lack true point-forecasts. Tracks pending state legislation on DC tax incentives and siting moratoria (already the source behind REG-10 and INC-10). Bills in committee are the leading indicator of jurisdiction-posture shifts. Treat as pipeline / early-warning, not projection.','Cataloged'),
('icprb-potomac-wma-water-supply-and-demand-data-center','ICPRB Potomac / WMA Water Supply & Demand — Data Center Study','Interstate Commission on the Potomac River Basin (ICPRB)','{"WTR — Water & Cooling"}','{"WTR-01","WTR-03","WTR-09"}',2050,'Long-Range (2045+)','Periodic','2025 (Data Centers & Water Use in the Potomac River Basin)','Yes — explicit DC load','Washington metropolitan area / Potomac River Basin (VA–MD–DC)','Mixed','High','Yes — Publisher archive','https://www.potomacriver.org/focus-areas/water-resources-and-drinking-water/water-resources/planning/data-centers-and-water-use-in-the-potomac-river-basin/','https://www.deq.virginia.gov/water/water-quantity/water-supply-planning','Only water forecast in the registry — alongside Ohio and Dominion — that models data-center demand explicitly. ICPRB projects DC share of Washington-metro water rising from ~8% (2025) toward ~25% (2035); average on-site use ~4→16 MGD and peak ~14.3→58 MGD. The Potomac supplies ~75% of the region''s water — the most concentrated DC-vs-drinking-water contention point on the East Coast. Highest-priority ingest for the WTR tier. Verify exact figures against the source before subscriber-facing use.','Priority Ingest'),
('utah-water-resources-plan-50-year-river-basin-plans','Utah Water Resources Plan (50-Year) + River Basin Plans','Utah Division of Water Resources','{"WTR — Water & Cooling"}','{"WTR-01","WTR-03"}',2072,'Long-Range (2045+)','Periodic','2021 Plan (finalized Feb 2022)','Partial — sector-level','Utah — statewide + river basins (Wasatch Front)','Mixed','Medium','Yes — Publisher archive','https://water.utah.gov/Planning/','https://water.utah.gov/wp-content/uploads/2022/01/2021-Water-Resources-Plan-Preliminary-Pages.pdf','50-year horizon (~2072). Division''s Water Demand Model projects M&I demand outstripping currently-developed supply ~2040 as population ~doubles to 6M by 2060. Legislative-audit scrutiny (2015 Auditor General) flags projection-reliability caveats — treat demand figures as contested. Wasatch Front (Salt Lake / Eagle Mountain) is the relevant DC corridor. VERIFY figures before subscriber-facing use.','Cataloged'),
('california-water-plan-update-2023-2028','California Water Plan (Update 2023 → 2028)','California Department of Water Resources (DWR)','{"WTR — Water & Cooling"}','{"WTR-01","WTR-03"}',2100,'Long-Range (2045+)','Periodic','Update 2023 (Update 2028 in progress)','Partial — sector-level','California statewide — by hydrologic region','Mixed','Medium','Yes — Publisher archive','https://water.ca.gov/programs/california-water-plan','https://water.ca.gov/Programs/California-Water-Plan/Update-2023','California''s DC growth (Silicon Valley, LA, Sacramento) sits under DWR''s WEAP future-scenarios model with scenarios extending toward 2072/2100. Update 2028 carries an interim goal to identify ~9 maf of additional supply / demand reduction by 2040. Sector-level rather than DC-explicit, but hydrologic-region granularity and an open-data explorer make it tractable for cooling-water siting overlays. Verify figures before subscriber-facing use.','Cataloged'),
('georgia-regional-water-plans-water-forecasting-dashboard','Georgia Regional Water Plans + Water Forecasting Dashboard','Georgia Environmental Protection Division (EPD)','{"WTR — Water & Cooling","PWR — Power & Energy"}','{"WTR-01","WTR-03 (+ energy-water intersection)"}',2060,'Long-Range (2045+)','Periodic','2023 Regional Water Plans','Partial — sector-level','Georgia — regional water planning councils (incl. Metro Atlanta)','Mixed','Medium','Yes — Publisher archive','https://waterplanning.georgia.gov/forecasting','https://waterplanning.georgia.gov/regional-water-plan','Forecasts Municipal, Industrial, Agricultural AND Energy water use in 10-year increments to 2060. The explicit Energy-sector water forecast makes this the registry''s clearest PWR×WTR intersection artifact. Clean vintage series (2011 / 2017 / 2023 regional plans) supports revision tracking.','Cataloged'),
('first-street-climate-risk-projections','First Street — Climate Risk Projections','First Street Foundation','{"ENV — Environmental Risk","WTR — Water & Cooling"}','{"ENV-04","ENV-06","ENV-09","forward hazard"}',2055,'Long-Range (2045+)','Periodic','Current models (property-level, ~30-yr forward)','No — infra baseline','United States (property / parcel-level, aggregable to jurisdiction)','API','Medium','No / Unknown','https://firststreet.org/',null,'Rare forward-looking, property-level physical climate risk — flood, wildfire, heat, wind — on a ~30-year horizon. The forward complement to FEMA NRI''s present-day composite. Parcel granularity lets ENV risk be projected for a specific candidate site, not just a county.','Cataloged'),
('icprb-washington-metro-water-supply-and-demand-study-data','ICPRB Washington Metro Water Supply & Demand Study (Data-Center Focus)','Interstate Commission on the Potomac River Basin (ICPRB)','{"WTR — Water & Cooling"}','{"WTR-01","WTR-03"}',2050,'Long-Range (2045+)','Periodic','2025 (WMA study + data-center water-use analysis)','Yes — explicit DC load','Washington metropolitan area / Potomac River Basin (VA, MD, DC, WV)','Mixed','High','Yes — Publisher archive','https://www.potomacriver.org/focus-areas/water-resources-and-drinking-water/water-resources/planning/data-centers-and-water-use-in-the-potomac-river-basin/','https://www.deq.virginia.gov/water/water-quantity/water-supply-planning','One of only two DC-explicit water forecasts in the registry (with Ohio). ICPRB projects data-center share of Washington-metro water use rising ~8% (2025) → ~25% (2035); avg on-site DC use 4 → 16 MGD; peak 14.3 → 58 MGD. Potomac supplies ~75% of the region. VERIFY figures before subscriber-facing use. Virginia''s statutory planning is mid-transition: 2020 HB542 created 26 regional planning areas; regional plans due to DEQ Oct 2029, next State Water Resources Plan within 2 yr after — so ICPRB is the usable DC-specific artifact NOW, ahead of the state cycle.','Priority Ingest'),
('nerc-long-term-reliability-assessment-ltra','NERC Long-Term Reliability Assessment (LTRA)','North American Electric Reliability Corporation','{"PWR — Power & Energy"}','{"PWR-04","PWR-08"}',2035,'Medium (8–12 yr)','Annual','2025 LTRA (2026–2035 horizon)','Partial — sector-level','North America (all NERC assessment areas)','PDF Only','High','Yes — Publisher archive','https://www.nerc.com/pa/RAPA/ra/Pages/default.aspx','https://www.nerc.com/pa/RAPA/ra/Pages/default.aspx','Ten-year continental reliability lens. The 2025 edition carried a sharp upward revision in summer-peak demand growth (large-load / DC-driven). Best cross-jurisdiction reliability-risk framing; pairs with ISO forecasts for the ''can the grid actually serve it'' question.','Validated'),
('fema-national-risk-index-nri','FEMA National Risk Index (NRI)','Federal Emergency Management Agency','{"ENV — Environmental Risk"}','{"ENV-01 through ENV-09 (composite hazard)"}',null,null,'Periodic','Current NRI release','No — infra baseline','United States (county + census tract)','Bulk Download','Low','Partial','https://hazards.fema.gov/nri/',null,'Not a forecast — the present-day composite hazard baseline already powering all nine ENV attributes (ENV-01…09). Included to anchor the ENV tier: FEMA NRI is the ''now'', First Street and NCA5 supply the ''forward''. That pairing is the ENV forecasting story.','Cataloged'),
('fifth-national-climate-assessment-nca5','Fifth National Climate Assessment (NCA5)','U.S. Global Change Research Program (USGCRP)','{"ENV — Environmental Risk","WTR — Water & Cooling"}','{"ENV composite","regional climate outlook"}',2100,'Long-Range (2045+)','Periodic','NCA5 (2023)','No — infra baseline','United States (10 regions + national)','Mixed','Low','Yes — Publisher archive','https://nca2023.globalchange.gov/',null,'Congressionally mandated, scenario-based U.S. climate assessment reaching to 2100 under multiple emissions pathways. Regional chapters give directional ENV/WTR context (heat, drought, water availability) for jurisdiction narratives. Authoritative but coarse — framing, not scoring.','Cataloged'),
('adwr-supply-and-demand-reports-assured-water-supply-aaws','ADWR Supply & Demand Reports + Assured Water Supply (AAWS)','Arizona Department of Water Resources (ADWR)','{"WTR — Water & Cooling"}','{"WTR-01","WTR-03","WTR-10"}',2075,'Long-Range (2045+)','Annual','2024 model update','Partial — sector-level','Arizona — by groundwater basin / Active Management Area (Phoenix AMA, Pinal AMA)','Mixed','High','Yes — Publisher archive','https://www.azwater.gov/supply-demand','https://www.azwater.gov/adwr-data-dashboards','Phoenix is a top-5 U.S. DC market on a groundwater-constrained aquifer. ADWR''s 100-year Assured Water Supply (AAWS) test is a hard statutory siting gate — a new large user must prove 100-yr supply. Revision signal is material: modeled unmet demand in the Phoenix AMA was revised from ~4.86 maf to ~3.6 maf between the June 2023 and June 2024 model runs. Annual cadence + basin granularity make this the best-refreshed Western-market water source in the registry. Verify figures before subscriber-facing use.','Priority Ingest'),
('regional-water-demand-forecast-for-northeastern-illinois-2020-2050','Regional Water Demand Forecast for Northeastern Illinois, 2020–2050','Chicago Metropolitan Agency for Planning (CMAP) + Illinois-Indiana Sea Grant; ISWS data','{"WTR — Water & Cooling"}','{"WTR-01","WTR-03"}',2050,'Long-Range (2045+)','Periodic','2024 update (2020–2050 series)','Partial — sector-level','Northeastern Illinois — 7-county Chicago region','Mixed','Medium','Yes — Publisher archive','https://iiseagrant.org/publications/regional-water-demand-forecast-for-northeastern-illinois-2020-2050/','https://datahub.cmap.illinois.gov/maps/598e59f7bc8040468734f7aa592824bd','Total regional withdrawals projected to reach 938 MGD by 2050 — an 8% decline from 2018 despite +1.4M residents / +300k jobs, driven by conservation/efficiency gains. Key DC-siting constraint is NOT aggregate demand but two hard limits: the U.S. Supreme Court Consent Decree cap on Illinois'' Lake Michigan withdrawals, and sandstone-aquifer withdrawals running ~2× recharge. Industrial/commercial self-suppliers ≥100k gpd report to IWIP — the data path for large-load (DC) tracking. VERIFY figures before subscriber-facing use.','Cataloged'),
('epri-powering-intelligence-data-center-load-study','EPRI — Powering Intelligence (Data Center Load Study)','Electric Power Research Institute','{"PWR — Power & Energy","Cross-Cutting Demand"}','{"Cross-cutting DC load"}',2030,'Medium (8–12 yr)','Ad hoc','2024','Yes — explicit DC load','United States (state-level scenarios)','PDF Only','Low','No / Unknown','https://www.epri.com/',null,'Four-scenario U.S. DC-load study to 2030 with state-level allocations. Useful for cross-checking which states absorb DC growth under high/low cases; not a recurring series, so limited revision value.','Cataloged'),
('central-ohio-regional-water-study','Central Ohio Regional Water Study','Ohio EPA + ODNR + Ohio Water Development Authority + MORPC (Hazen and Sawyer)','{"WTR — Water & Cooling"}','{"WTR-01","WTR-03"}',2050,'Long-Range (2045+)','Ad hoc','June 2025','Yes — explicit DC load','Central Ohio — 15-county MORPC region (Columbus)','Mixed','Medium','Yes — Publisher archive','https://www.morpc.org/programs-services/central-ohio-water-resources-planning/','https://dam.assets.ohio.gov/image/upload/epa.ohio.gov/Portals/0/water/central-ohio-regional-water-study-faq.pdf','Second DC-explicit water forecast alongside Virginia. Models 2030/2040/2050; 2040 chosen as primary planning horizon. Data centers projected to need ~70 MGD by 2040 (Intel + 100+ existing DCs). OASIS/integrated water-resources model with reservoir-online assumptions (R1/R3 online 2040). VERIFY figures before subscriber-facing use. Strong Priority-Ingest candidate given DC-specificity — flagged for Myke''s call.','Cataloged')
